import{_ as e,o,c as t,ae as r}from"./chunks/framework.C00B0EYs.js";const u=JSON.parse('{"title":"常见问题","description":"关于文件格式、限制与当前行为的常见问题。","frontmatter":{"title":"常见问题","description":"关于文件格式、限制与当前行为的常见问题。"},"headers":[],"relativePath":"zh/docs/guide/faq.md","filePath":"zh/docs/guide/faq.md"}'),d={name:"zh/docs/guide/faq.md"};function i(l,a,h,s,c,n){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="msep-是什么" tabindex="-1"><code>.msep</code> 是什么？ <a class="header-anchor" href="#msep-是什么" aria-label="Permalink to &quot;`.msep` 是什么？&quot;">​</a></h2><p><code>.msep</code> 是 Motor Sound Editor 使用的可编辑项目容器。它会把项目元数据、轨道定义、曲线数据和被引用音频打包在一起，便于整项目重开与迁移。</p><h2 id="轨道可分配哪些音频格式" tabindex="-1">轨道可分配哪些音频格式？ <a class="header-anchor" href="#轨道可分配哪些音频格式" aria-label="Permalink to &quot;轨道可分配哪些音频格式？&quot;">​</a></h2><p>当前版本支持：</p><ul><li><code>wav</code></li><li><code>ogg</code></li></ul><h2 id="为什么界面有牵引、惰行、制动三种状态-但只编辑牵引和制动曲线" tabindex="-1">为什么界面有牵引、惰行、制动三种状态，但只编辑牵引和制动曲线？ <a class="header-anchor" href="#为什么界面有牵引、惰行、制动三种状态-但只编辑牵引和制动曲线" aria-label="Permalink to &quot;为什么界面有牵引、惰行、制动三种状态，但只编辑牵引和制动曲线？&quot;">​</a></h2><p>因为试听系统暴露了三种模拟器状态，而当前创作模型只存储牵引与制动两套专用曲线。现版本中，惰行仍沿用牵引侧曲线进行试听。</p><h2 id="可以同时试听多条轨道吗" tabindex="-1">可以同时试听多条轨道吗？ <a class="header-anchor" href="#可以同时试听多条轨道吗" aria-label="Permalink to &quot;可以同时试听多条轨道吗？&quot;">​</a></h2><p>可以。只要轨道可听且已分配有效音频，试听引擎就支持分层同时播放。</p><h2 id="被隐藏的轨道还能听到吗" tabindex="-1">被隐藏的轨道还能听到吗？ <a class="header-anchor" href="#被隐藏的轨道还能听到吗" aria-label="Permalink to &quot;被隐藏的轨道还能听到吗？&quot;">​</a></h2><p>不能。在当前实现中，试听只使用“已启用、未静音、未隐藏”的轨道。</p><h2 id="替换轨道音频后-旧文件会一直保留在项目里吗" tabindex="-1">替换轨道音频后，旧文件会一直保留在项目里吗？ <a class="header-anchor" href="#替换轨道音频后-旧文件会一直保留在项目里吗" aria-label="Permalink to &quot;替换轨道音频后，旧文件会一直保留在项目里吗？&quot;">​</a></h2><p>不会。保存和另存为会清理未被引用音频，因此被替换掉的音频不会在 <code>.msep</code> 中持续累积。</p><h2 id="是否已有完成版设置页面" tabindex="-1">是否已有完成版设置页面？ <a class="header-anchor" href="#是否已有完成版设置页面" aria-label="Permalink to &quot;是否已有完成版设置页面？&quot;">​</a></h2><p>没有。代码层已经有设置存储，但当前用户可见版本尚无完成版设置界面。</p><h2 id="目前哪些导出目标可用" tabindex="-1">目前哪些导出目标可用？ <a class="header-anchor" href="#目前哪些导出目标可用" aria-label="Permalink to &quot;目前哪些导出目标可用？&quot;">​</a></h2><p>当前导出弹窗中，只有 BVE 可用；其他展示目标可见但不可选。</p><h2 id="我能只依赖导出-不保存-msep-吗" tabindex="-1">我能只依赖导出，不保存 <code>.msep</code> 吗？ <a class="header-anchor" href="#我能只依赖导出-不保存-msep-吗" aria-label="Permalink to &quot;我能只依赖导出，不保存 `.msep` 吗？&quot;">​</a></h2><p>不建议。<code>.msep</code> 是可编辑源项目；导出包是交付产物，不能替代可编辑主文件。</p>',20)])])}const m=e(d,[["render",i]]);export{u as __pageData,m as default};
